// Helper: extract text from OpenAI Responses API format or plain .text
const getEmailText = (nodeName) => {
    try {
          const d = $(nodeName).first().json;
          if (d.output && d.output[0] && d.output[0].content && d.output[0].content[0]) {
                  return d.output[0].content[0].text || '';
          }
          return d.text || '';
    } catch(e) { return ''; }
};

// 1. Get the email draft from whichever branch ran
let emailDraft = getEmailText('Hot lead email') ||
                   getEmailText('Nurture Email') ||
                   getEmailText('Relationship Building') ||
                   '';

if (!emailDraft || emailDraft === '') {
    emailDraft = 'No email draft was generated. Please compose manually.';
}

// FIX #5: Strip any "Subject:" line from the email body
// The AI sometimes includes Subject: in the body text - remove it
emailDraft = emailDraft.replace(/^Subject:.*\n?/im, '').trim();
// Append static signature
emailDraft = emailDraft + '\n\nBest regards,\n\nJuan Rivera\nPartner Account Director U.S. and LATAM\nTelesign\nMobile: 1-818-470-0546';

// 2. Get the analysis from the normalization node
const analysis = $('Normalize AI Output').first().json;

// 3. Get original webhook data
const webhookData = $('Webhook - Conference Data').first().json.body;

// 4. Get transcription
const transcription = $('Transcribe a recording').first().json.text || 'No transcription available';

// Use GPT-4o suggested subject line, fallback to MRC Vegas 2026
const subjectLine = analysis.suggested_subject_line || 'MRC Vegas 2026';

// FIX #3: Determine solution brief based on AI analysis
const solutionBrief = analysis.selected_solution_brief || null;

return {
    contactName: webhookData.contactName || 'Unknown',
    contactEmail: webhookData.email || 'Unknown',
    company: webhookData.company || 'Unknown',
    classification: analysis.classification || 'needs_clarification',
    confidence: analysis.confidence || 0,
    solutionBrief: solutionBrief,
    subjectLine: subjectLine,
    emailBody: emailDraft,
    transcription: transcription || 'No transcription available',
    keyInsights: analysis.key_insights || 'No insights available',
    status: 'pending_approval',
    timestamp: new Date().toISOString()
};

