let analysis;

if ($json.classification) {
    analysis = $json;
}
else if (typeof $json.text === 'string') {
    try {
          analysis = JSON.parse($json.text);
    } catch(e) {
          analysis = { classification: 'needs_clarification' };
    }
}
else if ($json.output && $json.output[0]?.content?.[0]?.text) {
    const raw = $json.output[0].content[0].text;
    if (typeof raw === 'object') {
          analysis = raw;
    } else if (typeof raw === 'string') {
          try {
                  analysis = JSON.parse(raw);
          } catch(e) {
                  analysis = { classification: 'needs_clarification' };
          }
    } else {
          analysis = { classification: 'needs_clarification' };
    }
}
else {
    analysis = { classification: 'needs_clarification' };
}

const validClassifications = [
    'qualified_lead',
    'content_nurture',
    'partnership_opportunity',
    'relationship_building',
    'needs_clarification'
  ];

if (!validClassifications.includes(analysis.classification)) {
    analysis.classification = 'needs_clarification';
}

return {
    classification: analysis.classification,
    confidence: analysis.confidence ?? null,
    selected_solution_brief: analysis.selected_solution_brief ?? null,
    key_insights: analysis.key_insights ?? null,
    suggested_subject_line: analysis.suggested_subject_line || 'MRC Vegas 2026',
    reasoning: analysis.reasoning ?? null
};

